const parseJson = (value, fallback) => {
  try {
    const parsed = JSON.parse(String(value || '').trim());
    return parsed ?? fallback;
  } catch {
    return fallback;
  }
};

const cfg = {
  lookbackHours: Number($json.lookbackHours || 24),
  maxChars: Number($json.maxChars || 1300),
  maxRegional: Number($json.maxRegional || 3),
  maxPolitics: Number($json.maxPolitics || 3),
  maxTech: Number($json.maxTech || 2),
  maxEconomy: Number($json.maxEconomy || 2),
  maxTraffic: Number($json.maxTraffic || 1),
  maxWarnings: Number($json.maxWarnings || 1),
  maxEnergy: Number($json.maxEnergy || 1),
  maxAi: Number($json.maxAi || 1),
  maxLinksTotal: Number($json.maxLinksTotal || 0),
  includeLinksHeadline: !!$json.includeLinksHeadline,
  includeLinksRegional: !!$json.includeLinksRegional,
  includeLinksPolitics: !!$json.includeLinksPolitics,
  includeLinksTech: !!$json.includeLinksTech,
  includeLinksEconomy: !!$json.includeLinksEconomy,
  includeLinksTraffic: !!$json.includeLinksTraffic,
  includeLinksWarnings: !!$json.includeLinksWarnings,
  includeLinksEnergy: !!$json.includeLinksEnergy,
  includeLinksAi: !!$json.includeLinksAi,
  includeLinksGeneral: !!$json.includeLinksGeneral,
  countryFocus: String($json.countryFocus || 'de')
};

const formatter = {
  topicOrder: parseJson($json.topicOrderJson, ['regional', 'politics', 'tech', 'economy', 'traffic', 'warnings', 'energy', 'ai']),
  sectionConfig: parseJson($json.sectionConfigJson, []),
  germanFocusRegex: String($json.germanFocusRegex || ''),
  scoreFreshnessHoursWindow: Number($json.scoreFreshnessHoursWindow || 48),
  scoreGermanFocus: Number($json.scoreGermanFocus || 25),
  scoreRegional: Number($json.scoreRegional || 20),
  scorePolitics: Number($json.scorePolitics || 14),
  scoreTech: Number($json.scoreTech || 10),
  headlineTitle: String($json.headlineTitle || 'Headline of the day'),
  footerLabelSources: String($json.footerLabelSources || 'Quellen'),
  footerLabelSkip: String($json.footerLabelSkip || 'Skip'),
  footerLabelIrrelevant: String($json.footerLabelIrrelevant || 'Irrelevant'),
  footerLabelError: String($json.footerLabelError || 'Fehler'),
  emptyMessage: String($json.emptyMessage || 'Heute keine relevanten News gefunden.')
};

const sources = parseJson($json.sourcesJson, []);

return sources.map((source) => ({
  json: {
    source,
    config: cfg,
    formatter
  }
}));

const src = $('Split Sources').item.json.source || {};
const config = $('Split Sources').item.json.config || {};
const formatter = $('Split Sources').item.json.formatter || {};

if ($json.error || $json.message) {
  return [{
    json: {
      config,
      formatter,
      sourceResult: {
        sourceId: src.sourceId || 'unknown',
        label: src.label || 'Unknown source',
        status: 'error',
        count: 0,
        items: [],
        error: String($json.message || $json.error || 'HTTP error')
      }
    }
  }];
}

const articles = Array.isArray($json.articles) ? $json.articles : [];
const items = articles
  .filter((a) => a && a.title && a.url)
  .map((a) => ({
    title: String(a.title).trim(),
    url: String(a.url).trim(),
    source: String(a?.source?.name || src.label || 'Quelle').trim(),
    sourceId: src.sourceId || 'unknown',
    publishedAt: a.publishedAt || null,
    topic: src.topic || 'general'
  }));

return [{
  json: {
    config,
    formatter,
    sourceResult: {
      sourceId: src.sourceId || 'unknown',
      label: src.label || 'Unknown source',
      status: 'ok',
      count: items.length,
      items,
      error: null
    }
  }
}];

const src = $('Split Sources').item.json.source || {};
const config = $('Split Sources').item.json.config || {};
const formatter = $('Split Sources').item.json.formatter || {};

if ($json.error || $json.message) {
  return [{
    json: {
      config,
      formatter,
      sourceResult: {
        sourceId: src.sourceId || 'unknown',
        label: src.label || 'Unknown source',
        status: 'error',
        count: 0,
        items: [],
        error: String($json.message || $json.error || 'HTTP error')
      }
    }
  }];
}

const normalizeText = (value) => String(value || '')
  .replace(/<!\[CDATA\[(.*?)\]\]>/gs, '$1')
  .replace(/<[^>]*>/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&quot;/g, '"')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

const raw = typeof $json === 'string'
  ? $json
  : String($json.data || $json.body || $json.response || '');

const items = [];
const itemRegex = /<item>([\s\S]*?)<\/item>/g;
let match;
while ((match = itemRegex.exec(raw)) !== null) {
  const block = match[1];
  const title = normalizeText((block.match(/<title>([\s\S]*?)<\/title>/i) || [])[1]);
  const link = normalizeText((block.match(/<link>([\s\S]*?)<\/link>/i) || [])[1]);
  const pubDateRaw = normalizeText((block.match(/<pubDate>([\s\S]*?)<\/pubDate>/i) || [])[1]);
  const publishedAt = pubDateRaw ? new Date(pubDateRaw).toISOString() : null;
  if (!title || !link) continue;
  items.push({
    title,
    url: link,
    source: src.label || 'Quelle',
    sourceId: src.sourceId || 'unknown',
    publishedAt,
    topic: src.topic || 'general'
  });
}

return [{
  json: {
    config,
    formatter,
    sourceResult: {
      sourceId: src.sourceId || 'unknown',
      label: src.label || 'Unknown source',
      status: 'ok',
      count: items.length,
      items,
      error: null
    }
  }
}];

const rows = $input.all().map((item) => item.json || {});
const sourceResults = rows.map((row) => row.sourceResult).filter(Boolean);

const base = rows[0] || {};

return [{
  json: {
    config: base.config || {},
    formatter: base.formatter || {},
    sourceResults
  }
}];

const cfg = $json.config || {};
const formatter = $json.formatter || {};
const sourceResults = Array.isArray($json.sourceResults) ? $json.sourceResults : [];

const toNumber = (v, fallback) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
};

const lookbackHours = Math.max(1, toNumber(cfg.lookbackHours, 24));
const maxChars = Math.max(300, toNumber(cfg.maxChars, 1300));
const now = Date.now();
const minTs = now - (lookbackHours * 60 * 60 * 1000);

const maxByTopic = {
  regional: Math.max(0, toNumber(cfg.maxRegional, 3)),
  politics: Math.max(0, toNumber(cfg.maxPolitics, 3)),
  tech: Math.max(0, toNumber(cfg.maxTech, 2)),
  economy: Math.max(0, toNumber(cfg.maxEconomy, 2)),
  traffic: Math.max(0, toNumber(cfg.maxTraffic, 1)),
  warnings: Math.max(0, toNumber(cfg.maxWarnings, 1)),
  energy: Math.max(0, toNumber(cfg.maxEnergy, 1)),
  ai: Math.max(0, toNumber(cfg.maxAi, 1))
};

const includeLinks = {
  headline: !!cfg.includeLinksHeadline,
  regional: !!cfg.includeLinksRegional,
  politics: !!cfg.includeLinksPolitics,
  tech: !!cfg.includeLinksTech,
  economy: !!cfg.includeLinksEconomy,
  traffic: !!cfg.includeLinksTraffic,
  warnings: !!cfg.includeLinksWarnings,
  energy: !!cfg.includeLinksEnergy,
  ai: !!cfg.includeLinksAi,
  general: !!cfg.includeLinksGeneral
};

let linksLeft = Math.max(0, toNumber(cfg.maxLinksTotal, 0));

const normalize = (s) => String(s || '').toLowerCase().replace(/https?:\/\/[^\s]+/g, '').replace(/[^a-z0-9aeiou\u00e4\u00f6\u00fc\u00df\s]/g, ' ').replace(/\s+/g, ' ').trim();

const topicOrder = Array.isArray(formatter.topicOrder) && formatter.topicOrder.length
  ? formatter.topicOrder
  : ['regional', 'politics', 'tech', 'economy', 'traffic', 'warnings', 'energy', 'ai'];

const allItems = [];
for (const source of sourceResults) {
  const items = Array.isArray(source?.items) ? source.items : [];
  for (const item of items) allItems.push(item);
}

const unique = [];
const seen = new Set();
for (const item of allItems) {
  const url = String(item.url || '').trim();
  const title = String(item.title || '').trim();
  if (!url || !title) continue;
  const key = `${url}|${normalize(title)}`;
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push(item);
}

const germanFocusRegex = new RegExp(formatter.germanFocusRegex || '(deutschland|europa|ulm|dornstadt)', 'i');

const scored = unique
  .map((item) => {
    const publishedTs = item.publishedAt ? Date.parse(item.publishedAt) : NaN;
    const isFresh = Number.isFinite(publishedTs) ? publishedTs >= minTs : true;
    if (!isFresh) return null;

    const title = String(item.title || '');
    const source = String(item.source || 'Quelle');
    const topic = String(item.topic || 'general');

    let score = 0;
    const freshnessWindow = Math.max(1, toNumber(formatter.scoreFreshnessHoursWindow, 48));
    if (Number.isFinite(publishedTs)) score += Math.max(0, freshnessWindow - ((now - publishedTs) / 3600000));
    if (germanFocusRegex.test(`${title} ${source}`)) score += Math.max(0, toNumber(formatter.scoreGermanFocus, 25));
    if (topic === 'regional') score += Math.max(0, toNumber(formatter.scoreRegional, 20));
    if (topic === 'politics') score += Math.max(0, toNumber(formatter.scorePolitics, 14));
    if (topic === 'tech') score += Math.max(0, toNumber(formatter.scoreTech, 10));

    return { ...item, topic, score, publishedTs: Number.isFinite(publishedTs) ? publishedTs : 0 };
  })
  .filter(Boolean)
  .sort((a, b) => (b.score - a.score) || (b.publishedTs - a.publishedTs));

const byTopic = {
  regional: [],
  politics: [],
  tech: [],
  economy: [],
  traffic: [],
  warnings: [],
  energy: [],
  ai: []
};

for (const item of scored) {
  if (byTopic[item.topic]) byTopic[item.topic].push(item);
}

const take = (arr, n) => arr.slice(0, Math.max(0, n));

const selected = {
  headline: scored[0] || null,
  regional: take(byTopic.regional, maxByTopic.regional),
  politics: take(byTopic.politics, maxByTopic.politics),
  tech: take(byTopic.tech, maxByTopic.tech),
  economy: take(byTopic.economy, maxByTopic.economy),
  traffic: take(byTopic.traffic, maxByTopic.traffic),
  warnings: take(byTopic.warnings, maxByTopic.warnings),
  energy: take(byTopic.energy, maxByTopic.energy),
  ai: take(byTopic.ai, maxByTopic.ai)
};

const formatItem = (item, withLink) => {
  const source = item.source ? ` - ${item.source}` : '';
  if (withLink && linksLeft > 0) {
    linksLeft -= 1;
    return `- ${item.title}${source}\n  ${item.url}`;
  }
  return `- ${item.title}${source}`;
};

const sections = [];

if (selected.headline) {
  sections.push({
    title: String(formatter.headlineTitle || 'Headline of the day'),
    lines: [formatItem(selected.headline, includeLinks.headline)]
  });
}

const sectionConfig = Array.isArray(formatter.sectionConfig) ? formatter.sectionConfig : [];
for (const conf of sectionConfig) {
  const items = selected[String(conf.key || '')] || [];
  if (!items.length) continue;
  const withLink = !!includeLinks[String(conf.key || '')] && linksLeft > 0;
  sections.push({
    title: String(conf.title || conf.key || 'Section'),
    lines: items.map((item) => formatItem(item, withLink))
  });
}

const blocks = [];
for (const sec of sections) blocks.push(`${sec.title}\n${sec.lines.join('\n')}`);

let messageCore = blocks.join('\n\n').trim();

const configuredSources = sourceResults.length;
const usedSources = sourceResults.filter((s) => Number(s.count || 0) > 0).length;
const skipSources = sourceResults.filter((s) => s.status === 'skipped').length;
const errorSources = sourceResults.filter((s) => s.status === 'error').length;
const irrelevantSources = sourceResults.filter((s) => s.status === 'ok' && Number(s.count || 0) === 0).length;

const footerParts = [];
if (skipSources > 0) footerParts.push(`${formatter.footerLabelSkip || 'Skip'} ${skipSources}`);
if (irrelevantSources > 0) footerParts.push(`${formatter.footerLabelIrrelevant || 'Irrelevant'} ${irrelevantSources}`);
if (errorSources > 0) footerParts.push(`${formatter.footerLabelError || 'Fehler'} ${errorSources}`);

const footer = [`${formatter.footerLabelSources || 'Quellen'} ${usedSources}/${configuredSources}`]
  .concat(footerParts.length ? [footerParts.join(' | ')] : [])
  .join('\n');

if (!messageCore) messageCore = String(formatter.emptyMessage || 'Heute keine relevanten News gefunden.');

let message = `${messageCore}\n\n${footer}`.trim();
if (message.length > maxChars) {
  const reserve = footer.length + 8;
  const allowedCore = Math.max(80, maxChars - reserve);
  const sliced = messageCore.slice(0, allowedCore).replace(/\s+[^\s]*$/, '').trim();
  message = `${sliced}...\n\n${footer}`;
}

const totalSelected = [
  selected.headline ? 1 : 0,
  ...topicOrder.map((k) => (selected[k] || []).length)
].reduce((acc, n) => acc + n, 0);

return [{
  json: {
    okToSend: totalSelected > 0,
    message,
    recipient: '',
    metrics: {
      configuredSources,
      usedSources,
      skipSources,
      irrelevantSources,
      errorSources,
      totalSelected
    },
    selected
  }
}];
